#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define WIDTH 16  
#define HEIGHT 16 
#define BLOCK_SIZE 16

#define ETA 0.3f       
#define MOMENTUM 0.3f  

inline float squash(float x)
{
    return 1.0f / (1.0f + exp(-x));
}

__kernel void bpnn_layerforward_ocl(__global float* input_units, __global float* output_units, __global float* input_weights,
                                   __global float* hidden_partial_sum, __local float* local_input, __local float* local_weights,
                                   const int input_n, const int hidden_n)
{
    int tx = get_local_id(0);
    int ty = get_local_id(1);
    int bx = get_group_id(0);
    int by = get_group_id(1);

    int block_size = BLOCK_SIZE;

    // Each work-group processes a tile of input_weights matrix

    // Load input units for this block into local memory
    int input_index = bx * block_size + tx;
    if(input_index <= input_n)
        local_input[tx] = input_units[input_index];
    else
        local_input[tx] = 0.0f;
    barrier(CLK_LOCAL_MEM_FENCE);

    // Load weights tile into local memory
    int weight_row = bx * block_size + tx;
    int weight_col = by * block_size + ty;

    if(weight_row <= input_n && weight_col <= hidden_n)
        local_weights[ty * block_size + tx] = input_weights[weight_row * (hidden_n + 1) + weight_col];
    else
        local_weights[ty * block_size + tx] = 0.0f;
    barrier(CLK_LOCAL_MEM_FENCE);

    // Compute partial sum for hidden node hidden_col (weight_col)
    float sum = 0.0f;
    if(weight_col <= hidden_n && (bx * block_size + tx) <= input_n)
    {
        for(int i = 0; i < block_size; i++)
        {
            sum += local_weights[i * block_size + ty] * local_input[i];
        }
    }

    // Write partial sums to global memory
    int partial_sum_index = by * (input_n / block_size + 1) + bx * block_size + tx;
    // But original code uses num_blocks * WIDTH, partial_sum[k * hid + j-1]
    // We'll store partial sums as partial_sum[block_id * hidden_n + hidden_node_index]

    // We'll write partial sums per work item per hidden unit
    // As per original host code, partial_sum has size num_blocks * WIDTH
    // We'll write partial_sum[bx * hidden_n + weight_col] = sum
    // But weight_col=by*block_size+ty, so for a single work-group, we must output sum per hidden node.

    // Since work-group dimension is 16x16, tx:0..15, ty:0..15
    // We'll write sum for ty-th hidden node index

    if(weight_col <= hidden_n && tx == 0)
    {
        // Each ty writes one partial sum
        hidden_partial_sum[bx * hidden_n + weight_col-1] = sum; // weight_col -1 because in original code indexing from 1
    }
}

// Kernel to adjust weights
__kernel void bpnn_adjust_weights_ocl(__global float* delta, const int ndelta,
                                      __global float* ly, const int nly,
                                      __global float* w, __global float* oldw)
{
    int j = get_global_id(0) + 1; // 1-based indexing for delta
    int k = get_global_id(1);     // from 0 to nly

    if(j <= ndelta && k <= nly)
    {
        int idx = k * (ndelta + 1) + j; // indexing w[k][j], 2D flattened, with dimension (nly+1)*(ndelta+1)

        float new_dw = ETA * delta[j] * ly[k] + MOMENTUM * oldw[idx];
        w[idx] += new_dw;
        oldw[idx] = new_dw;
    }
}
